// // This module implements a 4-bit binary counter with asynchronous reset and disable signals. The counter decrements on the negative edge of the clock when the disable signal is high. The counter resets to all ones when the reset signal is active.
module binary_counter (
    input clk,
    input reset,
    input en,
    output reg [3:0] count
);

always @(posedge clk or negedge reset) begin
    if (~reset)
        count <= 4'b0000;
    else if (en)
        count <= count + 1;
end

endmodule
